var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아하하……. 갑작스럽게 불려나와서 브리핑하려니 좀 긴장되네요.","JPN":"あはは……急に呼び出されてブリーフィングするって、ちょっと緊張しますね。","ENG":"Ahaha... Kinda nervous to suddenly get called in to do a briefing...","TWN":"哈哈哈……突然把人家找來做簡報，害我有點緊張呢～"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"크흠. 우선, 저희는 알파트릭스 바이오닉스에 대해 조사하고 있었는데 말이죠.","JPN":"ゴホン。まず、私たちはアルファトリックス・バイオニクスについて\\n調べていました。","ENG":"Ahem. First off, we did some investigating into Alphatrix’s Bionics.","TWN":"咳咳，我們一直有在調查阿爾法崔克斯仿生，"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"회사는 건실하게 운영되었지만, 몇 년 전부터 대표는 전혀 얼굴을 드러내지 않고 있었어요.","JPN":"会社は堅実に運営されていましたが、数年前から代表は\\nまったく公に顔を出していませんでした。","ENG":"The company itself has been operating well, but we found that the CEO hadn’t shown up there in years.","TWN":"公司的營運雖然沒什麼問題，但代表從幾年前開始就沒有再露過面。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"우연인지는 모르겠지만, 그 시점은 회장님의 사망 시기와 일치하고요.","JPN":"偶然かもしれませんが、そのタイミングは会長の死亡時期と\\n一致しています。","ENG":"I don’t know if it’s a coincidence or not, but that timeline coincides with the President’s passing.","TWN":"不知道是不是巧合，但會長也在同個時間點死亡。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그리고 또 하나 수상한 점이라면……","JPN":"そしてもう一つ怪しい点といえば……","ENG":"Another thing that seemed suspicious was...","TWN":"另外還有一點很可疑……"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"부회장님이 돌아가시기 전에 바이오닉스 대표의 지분 중 상당량이 처분된 뒤였어요.","JPN":"副会長が亡くなる前に、バイオニクス代表の持株の相当量を\\n処分したそうです。","ENG":"That a significant portion of the CEO of Bionics' shares were disposed of before the Vice Chairman died.","TWN":"就是在副會長遭到殺害前，仿生代表正好將持有的股份大量拋出。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그래서 그 돈이 흘러들어간 곳을 추적하던 중에 이상한 정황이 드러났어요.","JPN":"そして、そのお金の流れを追跡していたところ、不可解な状況が\\n明らかになりました。","ENG":"So we tracked where the money went and found something interesting.","TWN":"我們追查那筆錢的流向後，發現一件可疑的事。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"익명의 개인 투자자가 최근 막대한 자금으로 퓨처 앳 워의 지분을 매입하고 있다는 거죠.","JPN":"匿名の個人投資家が最近、莫大な資金でフューチャーアットウォーの\\n株を買収していたのです。","ENG":"Huge sums of money have been spent by an anonymous investor on Future-at-War shares.","TWN":"有一位匿名的投資人，最近大量買入天啟兵器的股份。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"저희는 그 개인 투자자가 알파트릭스 바이오닉스 대표와 관련이 있다고…….","JPN":"私たちはその個人投資家がアルファトリックス・バイオニクス代表と\\n関連があると……","ENG":"We suspect that this individual is somehow connected to the CEO of Bionics...","TWN":"我們懷疑，那位投資人和阿爾法崔克斯仿生的代表有關係……"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"갑자기 처들어와서 무슨 행패인가! 썩 안 나가!","JPN":"いきなり乱入してなんて乱暴な発言だ！　さっさと出ていけ！","ENG":"Are you here to waste our time or what?! Get out!!","TWN":"你們突然這樣衝進來，跟流氓有什麼兩樣！都給我滾出去！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"계속 들어보죠, 이사님.","JPN":"続きを聞いてみましょう、理事。","ENG":"Let’s first let her finish.","TWN":"理事，請繼續聽下去。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"계속하긴 뭘! 이 자리는 알파트릭스의 새로운 회장을 추대하는 이사회의야!","JPN":"続ける必要などない！\\nここはアルファトリックスの新しい会長を推戴する理事会だ！","ENG":"Let her finish?! This meeting was scheduled to discuss who will be the President of Alphatrix!","TWN":"聽什麼聽！董事會的職責，是要推選出阿爾法崔克斯的新任會長！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"주주들도 참석한 자리에서 저런 얼토당토 않은 비약을 늘어놔서 어쩌잔 건가!","JPN":"株主たちも出席している場で、あんなデタラメな憶測を並べてどうするつもりだ！","ENG":"Our shareholders are also present and you still want them to hear her sell us snake oil?!","TWN":"這麼多股東在場聽他們說那些毫無根據的推測，這是在幹什麼！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"당장 저 두 사람을 끌어내!","JPN":"今すぐあの二人を追い出せ！","ENG":"Get those two out of here this instant!","TWN":"立刻把那兩個人給我趕出去！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아뇨, 이사님. 저는 지금 제 권리를 행사 중이에요.","JPN":"それはできません、理事。私は今、自分の権利を行使しています。","ENG":"No, sir. I am just exercising my right.","TWN":"不可以，我正在行使我的權利。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"권리 행사라니……. 무슨 얘깁니까?","JPN":"権利の行使とは……どういうことでしょう？","ENG":"Your right? What are you talking about?","TWN":"行使什麼權利……你在說什麼？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저도 회장 후보로 입후보했잖아요?","JPN":"私も会長候補として立候補したでしょう？","ENG":"I am a candidate for the President seat, am I not?","TWN":"我不是會長候選人嗎？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};